func (a *app) handleTrack(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var p trackPayload
	dec := json.NewDecoder(http.MaxBytesReader(w, r.Body, 1<<20))
	dec.DisallowUnknownFields()
	if err := dec.Decode(&p); err != nil {
		http.Error(w, "invalid json", http.StatusBadRequest)
		return
	}

	if p.User == "" {
		p.User = r.Header.Get("X-User")
	}
	if p.RequestID == "" {
		p.RequestID = r.Header.Get("X-Request-ID")
	}
	if p.Operation == "" {
		p.Operation = r.URL.Query().Get("op")
	}

	if p.RequestID == "" {
		p.RequestID = a.nextRequestID()
	}
	if p.User == "" {
		p.User = "unknown"
	}
	if p.Operation == "" {
		p.Operation = "unknown"
	}

	method := r.Method
	path := r.URL.Path
	status := "200"

	user := a.sanitizeLabelValue("user", p.User)
	reqID := a.sanitizeLabelValue("request_id", p.RequestID)
	op := a.sanitizeLabelValue("operation", p.Operation)

	labels := p.Labels
	if labels == nil {
		labels = map[string]string{}
	}

	validated, ok := a.validateAndNormalizeUserLabels(labels)
	if !ok {
		a.m.invalidLabelsTotal.Inc()
		http.Error(w, "invalid labels", http.StatusBadRequest)
		return
	}

	metricLabels := prometheus.Labels{
		"user":       user,
		"request_id": reqID,
		"operation":  op,
		"method":     method,
		"path":       path,
		"status":     status,
	}

	if !a.limiter.allow("app_user_requests_total", metricLabels) || !a.limiter.allow("app_user_request_duration_seconds", metricLabels) {
		a.m.droppedSeriesTotal.Inc()
		http.Error(w, "series limit exceeded", http.StatusTooManyRequests)
		return
	}

	a.m.userRequestsTotal.With(metricLabels).Add(clampFinite(p.Value, 1))
	if p.Duration > 0 {
		a.m.userRequestDuration.With(metricLabels).Observe(clampFinite(p.Duration, 0))
	}

	if len(validated) > 0 {
		_ = validated
	}

	w.Header().Set("Content-Type", "application/json")
	_, _ = w.Write([]byte(`{"ok":true}`))
}

func (a *app) nextRequestID() string {
	n := atomic.AddUint64(&a.reqIDSeq, 1)
	return fmt.Sprintf("gen-%d-%d", time.Now().UnixNano(), n)
}

func (a *app) validateAndNormalizeUserLabels(in map[string]string) (map[string]string, bool) {
	if len(in) == 0 {
		return map[string]string{}, true
	}
	if a.policy.MaxLabelsPerMetric > 0 && len(in) > a.policy.MaxLabelsPerMetric {
		return nil, false
	}
	out := make(map[string]string, len(in))
	for k, v := range in {
		k = strings.TrimSpace(k)
		if k == "" {
			return nil, false
		}
		if a.policy.MaxLabelKeyLen > 0 && len(k) > a.policy.MaxLabelKeyLen {
			return nil, false
		}
		if !a.policy.AllowAnyUserProvidedLabels {
			if _, ok := a.policy.AllowedLabelKeys[k]; !ok {
				return nil, false
			}
		}
		out[k] = a.sanitizeLabelValue(k, v)
	}
	return out, true
}

func (a *app) sanitizeLabelValue(key, v string) string {
	v = strings.TrimSpace(v)
	if a.policy.MaxLabelValueLen > 0 && len(v) > a.policy.MaxLabelValueLen {
		v = v[:a.policy.MaxLabelValueLen]
	}
	if a.policy.HashLongLabelValues && a.policy.HashThreshold > 0 && len(v) > a.policy.HashThreshold {
		sum := sha256.Sum256([]byte(a.policy.HashSalt + "\x00" + key + "\x00" + v))
		v = "sha256:" + hex.EncodeToString(sum[:])
	}
	if v == "" {
		return "unknown"
	}
	return v
}

func clampFinite(v float64, defaultVal float64) float64 {
	if math.IsNaN(v) || math.IsInf(v, 0) {
		return defaultVal
	}
	return v
}